import os
from flask import Flask, request, jsonify
import pymysql

app = Flask(__name__)

# Cloud SQL instance connection settings
DB_HOST = 'your-cloudsql-instance-ip'
DB_USER = 'your-db-username'
DB_PASSWORD = 'your-db-password'
DB_NAME = 'your-db-name'

@app.route('/search', methods=['GET'])
def search():
    query_params = request.args.to_dict()
    
    # Construct dynamic SQL query from HTTP request parameters
    query = "SELECT * FROM your-table-name WHERE 1=1"
    
    for param, value in query_params.items():
        if value:
            query += f" AND {param} LIKE '%{value}%'"
    
    try:
        conn = pymysql.connect(
            host=DB_HOST,
            user=DB_USER,
            password=DB_PASSWORD,
            db=DB_NAME
        )
        
        cur = conn.cursor()
        cur.execute(query)
        results = cur.fetchall()
        
        return jsonify(results)
    
    except Exception as e:
        print(f"Error: {e}")
        return jsonify({"error": "Failed to execute query"}), 500
    
if __name__ == '__main__':
    app.run(debug=True)

